module asyn_fifo(
    input wclk,
    input rclk,
    input wrstn,
    input rrstn,
    input winc,
    input rinc,
    input wdata
);
// Control logic
reg [3:0] wptr, rptr;
wire [3:0] wptr_next, rptr_next;
reg [3:0] wptr_buff, rptr_buff;
// Write control logic
wire [3:0] waddr;
wire wfull;
always @(posedge wclk or negedge rst_n) begin
    if (!rst_n)
        wptr <= 4'd0;
    else
        wptr <= wptr_next;
end
assign waddr = wptr[2:0];
assign wptr_next = wptr + (winc & ~wfull);
// Read control logic
wire [3:0] raddr;
wire rempty;
always @(posedge rclk or negedge rst_n) begin
    if (!rst_n)
        rptr <= 4'd0;
    else
        rptr <= rptr_next;
end
assign raddr = rptr[2:0];
assign rptr_next = rptr + (rinc & ~rempty);
// Gray code conversion
wire [3:0] wptr_gray_next, rptr_gray_next;
assign wptr_gray_next = wptr_next ^ (wptr_next >> 1);
assign rptr_gray_next = rptr_next ^ (rptr_next >> 1);
// Pointer buffer
always @(posedge wclk or negedge rst_n) begin
    if (!rst_n)
        rptr_buff <= 4'd0;
    else
        rptr_buff <= rptr_gray_next;
end
always @(posedge rclk or negedge rst_n) begin
    if (!rst_n)
        wptr_buff <= 4'd0;
    else
        wptr_buff <= wptr_gray_next;
end
// Full and empty signal
assign wfull = (wptr_next == {~rptr_buff[3], rptr_buff[2:0]});
assign rempty = (rptr_next == wptr_buff);
// Dual-port RAM
dual_port_RAM #(16, 8) dual_port_RAM(
    .wclk(wclk),
    .wenc(winc & ~wfull),
    .waddr(waddr),
    .wdata(wdata),
    .rclk(rclk),
    .renc(rinc & ~rempty),
    .raddr(raddr),
    .rdata(rdata)
);
endmodule
